{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを本日（2026年5月13日）をもって正式発足とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例会議を毎週水曜日の10時より開催する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "移行方式として、拠点をグループ分けして段階的に切り替えるB案（段階移行）を採用する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "開発ベンダーとしてコマツバ・ソリューションズを選定する。",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D5",
      "content": "認証とマスタ配信の基盤について、サクラ商事との共同利用（第3案）を行う。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "本番リリースの目標日付を9月末から10月15日に変更する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "システム切り替え作業は土曜日の深夜帯に行う。",
      "decided_by": "沼田 賢一"
    },
    {
      "id": "D8",
      "content": "新システムでは既存のロール定義を流用し、新規設計は行わず稼働後の運用改善として別途検討する。",
      "decided_by": "芦田 巧"
    },
    {
      "id": "D9",
      "content": "障害発生時の一次受け窓口を品質保証部（QA）とする。",
      "decided_by": "白鳥 千夏"
    }
  ],
